    assertEq(cyclicalWM.exitCycleId(lp),     0);
}

function addUnderlyingToken(address underlyingToken, UnderlyingTokenConfig calldata config) external override lock {
    _onlyAdmin();
    _checkState(!_supportedUnderlyingTokens.contains(underlyingToken));

    uint8 tokenDecimals = TokenUtils.expectDecimals(underlyingToken);
    uint8 debtTokenDecimals = TokenUtils.expectDecimals(debtToken);

    _checkArgument(tokenDecimals <= debtTokenDecimals);

    _underlyingTokens[underlyingToken] = UnderlyingTokenParams({
        decimals:         tokenDecimals,
        conversionFactor: 10**(debtTokenDecimals - tokenDecimals),
        enabled:          false
    });

    _repayLimiters[underlyingToken] = Limiters.createLinearGrowthLimiter(
        config.repayLimitMaximum,
        config.repayLimitBlocks,
        config.repayLimitMinimum
    );

    _liquidationLimiters[underlyingToken] = Limiters.createLinearGrowthLimiter(
        config.liquidationLimitMaximum,
        config.liquidationLimitBlocks,
        config.liquidationLimitMinimum
    );

    _supportedUnderlyingTokens.add(underlyingToken);

    emit AddUnderlyingToken(underlyingToken);
}

function replaceEmergencySecurityCouncil(
    IGnosisSafe _prevSecurityCouncil,
    IGnosisSafe _newSecurityCouncil,
    uint256 _threshold,
    IUpgradeExecutor _upgradeExecutor
) internal {
    requireSafesEquivalent(_prevSecurityCouncil, _newSecurityCouncil, _threshold);
    bytes32 EXECUTOR_ROLE = _upgradeExecutor.EXECUTOR_ROLE();
    require(
        IAccessControlUpgradeable(address(_upgradeExecutor)).hasRole(
            EXECUTOR_ROLE, address(_prevSecurityCouncil)
        ),
        "SecurityCouncilMgmtUpgradeLib: prev council not executor"
    );
    require(
        !IAccessControlUpgradeable(address(_upgradeExecutor)).hasRole(
            EXECUTOR_ROLE, address(_newSecurityCouncil)
        ),
        "SecurityCouncilMgmtUpgradeLib: new council already executor"
    );

    IAccessControlUpgradeable(address(_upgradeExecutor)).revokeRole(
        EXECUTOR_ROLE, address(_prevSecurityCouncil)
    );
    IAccessControlUpgradeable(address(_upgradeExecutor)).grantRole(
        EXECUTOR_ROLE, address(_newSecurityCouncil)
    );
}

function initiateModifyTimelockExpiration(
  bytes4 functionSelector, uint256 newTimelockExpiration, uint256 extraTime
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Ensure that the supplied default expiration does not exceed 1 month.
  require(
    newTimelockExpiration <= 30 days,
    "New timelock expiration cannot exceed one month."
  );

  // Ensure a timelock expiration under one hour is not set on this function.
  if (functionSelector == this.modifyTimelockExpiration.selector) {
    require(
      newTimelockExpiration >= 60 minutes,
      "Expiration of modifyTimelockExpiration must be at least an hour long."
    );
  }

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.modifyTimelockExpiration.selector,
    abi.encode(functionSelector, newTimelockExpiration),
    extraTime
  );
}

function execute(
  bytes calldata data,
  address executor,
  uint256 gasLimit,
  bytes calldata signatures
) external returns (bool success, bytes memory returnData) {
  require(
    executor == msg.sender || executor == address(0),
    "Must call from the executor account if one is specified."
  );

  // Derive the message hash and wrap in the eth signed messsage hash.
  bytes32 hash = _toEthSignedMessageHash(
    _getHash(data, executor, gasLimit, _nonce)
  );

  // Recover each signer from the provided signatures.
  address[] memory signers = _recoverGroup(hash, signatures);

  require(signers.length == _THRESHOLD, "Total signers must equal threshold.");

  // Verify that each signatory is an owner and is strictly increasing.
  address lastAddress = address(0); // cannot have address(0) as an owner
  for (uint256 i = 0; i < signers.length; i++) {
    require(
      _isOwner[signers[i]], "Signature does not correspond to an owner."
    );
    require(
      signers[i] > lastAddress, "Signer addresses must be strictly increasing."
    );
    lastAddress = signers[i];
  }

  // Increment the nonce and execute the transaction.
  _nonce++;
  (success, returnData) = _DESTINATION.call.gas(gasLimit)(data);
}

function verifyKeyWithDS(
    bytes memory keyname,
    RRUtils.RRIterator memory dsrrs,
    RRUtils.DNSKEY memory dnskey,
    bytes memory keyrdata
) internal view returns (bool) {
    uint16 keytag = keyrdata.computeKeytag();
    for (; !dsrrs.done(); dsrrs.next()) {
        bytes memory proofName = dsrrs.name();
        if (!proofName.equals(keyname)) {
            revert ProofNameMismatch(keyname, proofName);
        }

        RRUtils.DS memory ds = dsrrs.data.readDS(
            dsrrs.rdataOffset,
            dsrrs.nextOffset - dsrrs.rdataOffset
        );
        if (ds.keytag != keytag) {
            continue;
        }
        if (ds.algorithm != dnskey.algorithm) {
            continue;
        }

        Buffer.buffer memory buf;
        buf.init(keyname.length + keyrdata.length);
        buf.append(keyname);
        buf.append(keyrdata);
        if (verifyDSHash(ds.digestType, buf.buf, ds.digest)) {
            return true;
        }
    }
    return false;
}

function _resolveName(
    address addr
) internal view override returns (string memory name) {
    name = IStandaloneReverseRegistrar(chainRegistrar).nameForAddr(addr);
    if (bytes(name).length > 0) {
        return name;
    }
    bytes32 node = NameCoder.namehash(
        ADDR_REVERSE_NODE,
        keccak256(bytes(HexUtils.addressToHex(addr)))
    );
    address resolver = ens.resolver(node);
    if (resolver != address(0)) {
        // note: this only supports onchain direct calls (no extended, no offchain)
        (bool ok, bytes memory v) = resolver.staticcall{gas: 100_000}(
            abi.encodeCall(INameResolver.name, (node))
        );
        if (ok) {
            (ok, v) = LibABI.tryDecodeBytes(v);
        }
        if (!ok) {
            return ""; // terminate on revert or decode failure
        }
        if (v.length > 0) {
            return string(v);
        }
    }
    return defaultRegistrar.nameForAddr(addr);
}

function renew(
    uint256 tokenId,
    uint256 duration
) external onlyController returns (uint256 expires) {
    bytes32 node = _makeNode(ETH_NODE, bytes32(tokenId));

    uint256 registrarExpiry = registrar.renew(tokenId, duration);

    // Do not set anything in wrapper if name is not wrapped
    try registrar.ownerOf(tokenId) returns (address registrarOwner) {
        if (
            registrarOwner != address(this) ||
            ens.owner(node) != address(this)
        ) {
            return registrarExpiry;
        }
    } catch {
        return registrarExpiry;
    }

    // Set expiry in Wrapper
    uint64 expiry = uint64(registrarExpiry) + GRACE_PERIOD;

    // Use super to allow names expired on the wrapper, but not expired on the registrar to renew()
    (address owner, uint32 fuses, ) = super.getData(uint256(node));
    _setData(node, owner, fuses, expiry);

    return registrarExpiry;
}

function assertEqCall(
    address targetA,
    bytes memory callDataA,
    address targetB,
    bytes memory callDataB,
    bool strictRevertData
) internal virtual {
    (bool successA, bytes memory returnDataA) = address(targetA).call(callDataA);
    (bool successB, bytes memory returnDataB) = address(targetB).call(callDataB);

    if (successA && successB) {
        assertEq(returnDataA, returnDataB, "Call return data does not match");
    }

    if (!successA && !successB && strictRevertData) {
        assertEq(returnDataA, returnDataB, "Call revert data does not match");
    }

    if (!successA && successB) {
        emit log("Error: Calls were not equal");
        emit log_named_bytes("  Left call revert data", returnDataA);
        emit log_named_bytes(" Right call return data", returnDataB);
        revert("assertion failed");
    }

    if (successA && !successB) {
        emit log("Error: Calls were not equal");
        emit log_named_bytes("  Left call return data", returnDataA);
        emit log_named_bytes(" Right call revert data", returnDataB);
        revert("assertion failed");
    }
}

